import type { Order, OrderStatus, PaymentEvent } from "./types";

const statusByType: Record<PaymentEvent["type"], OrderStatus> = {
  payment_pending: "pending",
  payment_succeeded: "paid",
  payment_failed: "failed",
};

function shouldUpdateOrder(existing: Order | undefined, nextStatus: OrderStatus): boolean {
  if (!existing) return true;
  if (existing.status === "paid" || existing.status === "failed") {
    return false;
  }
  return true;
}

export function handlePaymentEvent(store: PaymentStore, event: PaymentEvent): void {
  if (store.hasProcessedEvent(event.eventId)) {
    return;
  }

  const nextStatus = statusByType[event.type];
  const existingOrder = store.getOrder(event.orderId);
  const shouldUpdate = shouldUpdateOrder(existingOrder, nextStatus);

  if (shouldUpdate) {
    store.upsertOrder({
      orderId: event.orderId,
      status: nextStatus,
      amountCents: event.amountCents,
    });
  }

  if (event.type === "payment_succeeded" && shouldUpdate && existingOrder?.status !== "paid") {
    store.recordCharge(event.orderId, event.amountCents);
  }

  store.markEventProcessed(event.eventId);
}
